cat > /tmp/explore_api.cs << 'EOF'
using System;
using System.Reflection;
using System.Linq;

var agentsAiDll = "/home/runner/.nuget/packages/microsoft.agents.ai/1.5.0/lib/net8.0/Microsoft.Agents.AI.dll";
var extensionsAiDll = "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.2/lib/net8.0/Microsoft.Extensions.AI.dll";

Console.WriteLine("=== MICROSOFT.AGENTS.AI PUBLIC TYPES ===\n");
var agentsAssembly = Assembly.LoadFrom(agentsAiDll);
var agentsTypes = agentsAssembly.GetTypes()
    .Where(t => (t.IsPublic || t.IsNestedPublic) && !t.Name.StartsWith("<"))
    .OrderBy(t => t.Namespace)
    .ThenBy(t => t.Name);

foreach (var type in agentsTypes)
{
    Console.WriteLine($"\n{type.Namespace}.{type.Name}");

    if (type.IsClass || type.IsInterface || type.IsEnum)
    {
        // Show constructors for classes
        if (type.IsClass)
        {
            var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
            if (constructors.Length > 0)
            {
                foreach (var ctor in constructors.Take(1))
                {
                    var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"  .ctor({@params})");
                }
            }
        }

        // Show public methods (limited)
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .Where(m => !m.IsSpecialName)
            .Take(5);
        foreach (var method in methods)
        {
            var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name}"));
            Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({@params})");
        }
    }
}

Console.WriteLine("\n\n=== MICROSOFT.EXTENSIONS.AI PUBLIC TYPES (Selected) ===\n");
var extAssembly = Assembly.LoadFrom(extensionsAiDll);
var extTypes = extAssembly.GetTypes()
    .Where(t => (t.IsPublic || t.IsNestedPublic) && !t.Name.StartsWith("<"))
    .Where(t => t.Name.Contains("Chat") || t.Name.Contains("Tool") || t.Name.Contains("Function") || t.Name.Contains("Options") || t.Name.Contains("AIFunction"))
    .OrderBy(t => t.Namespace)
    .ThenBy(t => t.Name);

foreach (var type in extTypes)
{
    Console.WriteLine($"\n{type.Namespace}.{type.Name}");
    if (type.IsClass || type.IsInterface)
    {
        var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        if (constructors.Length > 0 && type.IsClass)
        {
            foreach (var ctor in constructors.Take(1))
            {
                var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                Console.WriteLine($"  .ctor({@params})");
            }
        }
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .Where(m => !m.IsSpecialName)
            .Take(4);
        foreach (var method in methods)
        {
            var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name}"));
            Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({@params})");
        }
    }
}
