using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

// Load the assemblies from the built project bin
var binPath = "/tmp/sv-77fa74c7402e4ad19e73eecbcd7fcaa1/ResearchAgent/bin/Debug/net10.0/";

Console.WriteLine("=== MICROSOFT.AGENTS.AI PUBLIC TYPES & MEMBERS ===\n");

var agentsAssembly = Assembly.LoadFrom(System.IO.Path.Combine(binPath, "Microsoft.Agents.AI.dll"));
var agentsTypes = agentsAssembly.GetTypes()
    .Where(t => (t.IsPublic || t.IsNestedPublic) && !t.Name.StartsWith("<"))
    .OrderBy(t => t.Namespace)
    .ThenBy(t => t.Name)
    .ToList();

var keyTypes = new[] { "Agent", "ChatClientAgent", "Tool", "AIFunction", "AgentInvokeOptions", "Options" };

foreach (var type in agentsTypes.Where(t => keyTypes.Any(k => t.Name.Contains(k)) || t.Namespace.Contains("Agent")))
{
    Console.WriteLine($"\n{'='} {type.Namespace}.{type.Name} {(type.IsInterface ? "(Interface)" : type.IsClass ? "(Class)" : "")} ===");

    // Show constructors for classes
    if (type.IsClass)
    {
        var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        if (constructors.Length > 0)
        {
            Console.WriteLine("  Constructors:");
            foreach (var ctor in constructors.Take(3))
            {
                var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                Console.WriteLine($"    .ctor({@params})");
            }
        }
    }

    // Show properties
    var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static);
    if (properties.Length > 0)
    {
        Console.WriteLine("  Properties:");
        foreach (var prop in properties.Take(5))
        {
            Console.WriteLine($"    {prop.PropertyType.Name} {prop.Name} {{ get; set; }}");
        }
    }

    // Show public methods (limited)
    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName)
        .ToList();
    if (methods.Count > 0)
    {
        Console.WriteLine("  Methods:");
        foreach (var method in methods.Take(5))
        {
            var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({@params})");
        }
    }
}

Console.WriteLine("\n\n=== ALL MICROSOFT.AGENTS.AI TYPES ===\n");
foreach (var type in agentsTypes)
{
    Console.WriteLine($"{type.Namespace}.{type.Name}");
}

Console.WriteLine("\n\n=== MICROSOFT.EXTENSIONS.AI KEY TYPES ===\n");
var extAssembly = Assembly.LoadFrom(System.IO.Path.Combine(binPath, "Microsoft.Extensions.AI.dll"));
var extTypes = extAssembly.GetTypes()
    .Where(t => (t.IsPublic || t.IsNestedPublic) && !t.Name.StartsWith("<"))
    .OrderBy(t => t.Namespace)
    .ThenBy(t => t.Name)
    .ToList();

var extKeyTypes = new[] { "Chat", "Tool", "AIFunction", "Options", "Embedding", "Client" };
foreach (var type in extTypes.Where(t => extKeyTypes.Any(k => t.Name.Contains(k))))
{
    Console.WriteLine($"{type.Namespace}.{type.Name}");
}
EOF
