using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(
        ([Description("A concise label for this note")] string title,
         [Description("The content to save")] string content) =>
        {
            notebook.Add(title, content);
            return $"Saved note: {title}";
        },
        "save_note",
        "Save a research note for later reference in the summary."),
    AIFunctionFactory.Create(
        () => notebook.GetAll(),
        "get_notes",
        "Retrieve all saved research notes."),
};

const string instructions = """
    You are a research agent. Given a topic, you:
    1. Search the web for relevant information using the search_web tool.
    2. Save key findings as notes using the save_note tool.
    3. After gathering enough information (at least 3 searches), retrieve your
       notes with get_notes and produce a well-structured summary with sources.
    Be thorough but concise. Always cite your sources.
    """;

ChatClientAgent agent = chatClient.AsAIAgent(
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and summarizing findings.",
    tools: tools);

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic (or press Enter for default): ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    topic = "Recent advances in quantum computing 2025";
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

AgentResponse response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"Notes collected: {notebook.Count}");

// ──────────────────────────────────────────────
// Tool implementations
// ──────────────────────────────────────────────

[Description("Search the web for information on a query. Returns a list of result snippets.")]
static string SearchWeb(
    [Description("The search query")] string query)
{
    // In production, call a real search API (Bing, Google, etc.).
    // This stub returns plausible results so the agent loop works end-to-end.
    Console.WriteLine($"  🔍  Searching: \"{query}\"");

    var results = new[]
    {
        new
        {
            Title = $"Latest Research on {query} - Science Daily",
            Snippet = $"Recent studies show significant progress in {query}. " +
                      "Researchers have made breakthroughs that could transform the field. " +
                      "Key developments include improved efficiency and novel approaches.",
            Url = $"https://example.com/science/{Uri.EscapeDataString(query)}"
        },
        new
        {
            Title = $"{query}: A Comprehensive Overview - Nature",
            Snippet = $"A comprehensive review of {query} reveals multiple promising directions. " +
                      "Experts predict rapid advancement in the next decade with applications " +
                      "spanning industry, healthcare, and fundamental research.",
            Url = $"https://example.com/nature/{Uri.EscapeDataString(query)}"
        },
        new
        {
            Title = $"Industry Applications of {query} - TechReview",
            Snippet = $"Major companies are investing heavily in {query}. " +
                      "Commercial applications are expected within 3-5 years. " +
                      "Funding has increased by 40% year-over-year.",
            Url = $"https://example.com/tech/{Uri.EscapeDataString(query)}"
        }
    };

    return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
}

// ──────────────────────────────────────────────
// Notebook helper
// ──────────────────────────────────────────────

sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    public void Add(string title, string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝  Note saved: \"{title}\"");
    }

    public string GetAll()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"[Note {i + 1}] {n.Title}\n{n.Content}"));
    }
}

