     .AsIChatClient();

 var notebook = new Notebook();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(SearchWeb),
     AIFunctionFactory.Create(
         ([Description("A concise label for this note")] string title,
          [Description("The content to save")] string content) =>
         {
             notebook.Add(title, content);
             return $"Saved note: {title}";
         },
         "save_note",
         "Save a research note for later reference in the summary."),
     AIFunctionFactory.Create(
         () => notebook.GetAll(),
         "get_notes",
         "Retrieve all saved research notes."),
 };

 const string instructions = """
     You are a research agent. Given a topic, you:
     1. Search the web for relevant information using the search_web tool.
     2. Save key findings as notes using the save_note tool.
     3. After gathering enough information (at least 3 searches), retrieve your
        notes with get_notes and produce a well-structured summary with sources.
     Be thorough but concise. Always cite your sources.
     """;

 ChatClientAgent agent = chatClient.AsAIAgent(
     instructions: instructions,
     name: "ResearchAgent",
     description: "Researches a topic by searching the web and summarizing findings.",
     tools: tools);

 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 2048,
 });

 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       AI Research Agent (MAF)        ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine();
 Console.Write("Enter a research topic (or press Enter for default): ");
 var topic = Console.ReadLine();
 if (string.IsNullOrWhiteSpace(topic))
 {
     topic = "Recent advances in quantum computing 2025";
 }

 Console.WriteLine();
 Console.WriteLine($"Researching: {topic}");
 Console.WriteLine(new string('─', 50));

 AgentResponse response = await agent.RunAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     options: runOptions);

 Console.WriteLine();
 Console.WriteLine(response.Text);
 Console.WriteLine();
 Console.WriteLine(new string('─', 50));
 Console.WriteLine($"Notes collected: {notebook.Count}");

