 [Description("Search the web for information on a query. Returns a list of result snippets.")]
 static string SearchWeb(
     [Description("The search query")] string query)
 {
     // In production, call a real search API (Bing, Google, etc.).
     // This stub returns plausible results so the agent loop works end-to-end.
     Console.WriteLine($"  🔍  Searching: \"{query}\"");

     var results = new[]
     {
         new
         {
             Title = $"Latest Research on {query} - Science Daily",
             Snippet = $"Recent studies show significant progress in {query}. " +
                       "Researchers have made breakthroughs that could transform the field. " +
                       "Key developments include improved efficiency and novel approaches.",
             Url = $"https://example.com/science/{Uri.EscapeDataString(query)}"
         },
         new
         {
             Title = $"{query}: A Comprehensive Overview - Nature",
             Snippet = $"A comprehensive review of {query} reveals multiple promising directions. " +
                       "Experts predict rapid advancement in the next decade with applications " +
                       "spanning industry, healthcare, and fundamental research.",
             Url = $"https://example.com/nature/{Uri.EscapeDataString(query)}"
         },
         new
         {
             Title = $"Industry Applications of {query} - TechReview",
             Snippet = $"Major companies are investing heavily in {query}. " +
                       "Commercial applications are expected within 3-5 years. " +
                       "Funding has increased by 40% year-over-year.",
             Url = $"https://example.com/tech/{Uri.EscapeDataString(query)}"
         }
     };

     return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
 }

 // ──────────────────────────────────────────────
 // Notebook helper
 // ──────────────────────────────────────────────

 sealed class Notebook
 {
     private readonly List<(string Title, string Content)> _notes = [];

     public int Count => _notes.Count;

     public void Add(string title, string content)
     {
         _notes.Add((title, content));
         Console.WriteLine($"  📝  Note saved: \"{title}\"");
     }

     public string GetAll()
     {
         if (_notes.Count == 0)
         {
             return "No notes saved yet.";
         }

         return string.Join("\n\n", _notes.Select((n, i) =>
             $"[Note {i + 1}] {n.Title}\n{n.Content}"));
     }
 }
